mapper.select:
select 
from question


        and course_id = #{courseId}


        and type_id = #{typeId}


        and teacher_id = #{teacherId}


        and title like concat('%', #{title}, '%')


        and difficulty = #{difficulty}


        and status = #{status}


order by create_time desc

mapper.update:
update question
course_id = #{courseId}, course_name = #{courseName}, type_id = #{typeId}, type_name = #{typeName}, title = #{title}, option_a = #{optionA}, option_b = #{optionB}, option_c = #{optionC}, option_d = #{optionD}, option_e = #{optionE}, option_f = #{optionF}, answer = #{answer}, analysis = #{analysis}, score = #{score}, difficulty = #{difficulty}, status = #{status},
where id = #{id}
